/**
 * Creates an account and records the audit event atomically.
 *
 * @accountData struct   New account fields.
 * @return numeric
 * @throws application When insert or audit fails.
 */
public numeric function createAccountWithAudit(required struct accountData) {
  var newId = 0;

  transaction {
    try {
      newId = variables.accountRepository.insert(arguments.accountData);
      variables.auditService.log('account_created', newId);
    } catch (database dbEx) {
      throw(type='application', message='Account creation failed.', detail=dbEx.message);
    }
  }

  return newId;
}

wrong:
// Wrong: two separate calls — audit can fail after insert leaving orphaned account
public numeric function createAccountWithAudit(required struct accountData) {
  var newId = variables.accountRepository.insert(arguments.accountData);
  variables.auditService.log('account_created', newId);
  return newId;
}

