/**
 * Places an order and decrements inventory atomically.
 *
 * @orderData struct   Order fields.
 * @return numeric
 * @throws application When either write fails.
 */
public numeric function placeOrder(required struct orderData) {
  var orderId = 0;

  transaction {
    try {
      orderId = variables.orderRepository.insert(arguments.orderData);
      variables.inventoryRepository.decrement(arguments.orderData.productId, arguments.orderData.quantity);
    } catch (database dbEx) {
      throw(type='application', message='Order placement failed.', detail=dbEx.message);
    }
  }

  return orderId;
}

wrong:
// Wrong: two repo calls without a transaction — inventory can decrement without a committed order
public numeric function placeOrder(required struct orderData) {
  var orderId = variables.orderRepository.insert(arguments.orderData);
  variables.inventoryRepository.decrement(arguments.orderData.productId, arguments.orderData.quantity);
  return orderId;
}

