/**
 * Transfers balance between accounts; rolls back on any failure.
 *
 * @fromId numeric   Source account identifier.
 * @toId numeric     Target account identifier.
 * @amount numeric   Transfer amount in cents.
 * @return void
 * @throws application When balance is insufficient or transfer fails.
 */
public void function transfer(required numeric fromId, required numeric toId, required numeric amount) {
  transaction {
    try {
      var fromBalance = variables.accountRepository.getBalance(arguments.fromId);
      if (fromBalance < arguments.amount) {
        throw(type='application', message='Insufficient balance.');
      }
      variables.accountRepository.debit(arguments.fromId, arguments.amount);
      variables.accountRepository.credit(arguments.toId, arguments.amount);
    } catch (database dbEx) {
      throw(type='application', message='Transfer failed.', detail=dbEx.message);
    }
  }
}

/**
 * Inserts all notification items in one atomic transaction.
 *
 * @items array   Notification structs to persist.
 * @return void
 * @throws application When any insert fails.
 */
public void function bulkInsertNotifications(required array items) {
  transaction {
    try {
      arguments.items.each(function(required struct item) {
        variables.notificationRepository.insert(item);
      });
    } catch (database dbEx) {
      throw(type='application', message='Bulk notification insert failed.', detail=dbEx.message);
    }
  }
}

