/**
 * Creates an invite and returns the new record ID.
 *
 * @email string   Invited email address.
 * @return numeric
 */
public numeric function createInvite(required string email) {
  var newId = 0;

  transaction {
    queryExecute(
      'INSERT INTO user_invites (email, createdAt) VALUES (:email, :now)',
      { email: { value: arguments.email, cfsqltype: 'cf_sql_varchar' }, now: { value: now(), cfsqltype: 'cf_sql_timestamp' } },
      { datasource: variables.datasource }
    );
    var idResult = queryExecute('SELECT SCOPE_IDENTITY() AS newId', {}, { datasource: variables.datasource });
    newId = idResult.newId;
  }

  return newId;
}

/**
 * Persists a profile update with typed exception remapping.
 *
 * @userId numeric        User identifier.
 * @profileData struct    Fields to update.
 * @return void
 * @throws application When the profile update fails.
 */
public void function updateProfile(required numeric userId, required struct profileData) {
  transaction {
    try {
      variables.userRepository.updateProfile(arguments.userId, arguments.profileData);
    } catch (database dbEx) {
      throw(type='application', message='Profile update is unavailable. Please try again.', detail=dbEx.message);
    }
  }
}

/**
 * Activates a user account and dispatches a welcome notification atomically.
 *
 * @userId numeric   Target user identifier.
 * @return void
 * @throws application When activation or notification dispatch fails.
 */
public void function activateUser(required numeric userId) {
  transaction {
    try {
      variables.userRepository.setStatus(arguments.userId, 'active');
      variables.notificationService.dispatch('welcome', arguments.userId);
    } catch (database dbEx) {
      throw(type='application', message='User activation failed.', detail=dbEx.message);
    }
  }
}

/**
 * Creates a job record and verifies it is readable post-commit.
 *
 * @jobData struct   Job fields to persist.
 * @return struct
 * @throws application When insert or post-commit verification fails.
 */
public struct function createJob(required struct jobData) {
  var jobId = 0;

  transaction {
    try {
      jobId = variables.jobRepository.insert(arguments.jobData);
    } catch (database dbEx) {
      throw(type='application', message='Job creation failed.', detail=dbEx.message);
    }
  }

  var job = variables.jobRepository.findById(jobId);
  if (isNull(job)) {
    throw(type='application', message='Job created but could not be verified.');
  }
  return job;
}
